def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 3:
            for p in range(1, 5):
                score += (ratio ** p) / (p * np.log(p + 1))
            score += np.tanh(ratio) * 10
        elif 2 < ratio <= 3:
            acc = 0
            for j in range(1, 10):
                acc += np.sin(ratio * j) / (j ** 2 + 1)
            score = acc * 5 + np.exp(-ratio)
        elif 1 < ratio <= 2:
            val = 0
            for k in range(1, 8):
                val += ((ratio - 1) ** k) / (k + 0.5)
            score = val * 12 + np.cos(ratio * np.pi * 3)
        elif 0.5 < ratio <= 1:
            sum_exp = 0
            for m in range(1, 15):
                sum_exp += np.exp(-m * (1 - ratio)) / (m + 1)
            score = sum_exp * 7 + np.sin(ratio * np.pi * 7)
        elif 0.2 < ratio <= 0.5:
            prod_log = 1
            count = 0
            for n in range(1, 15):
                val = ratio + n * 0.03
                if val < 1:
                    prod_log *= np.abs(np.log(1 - val + 1e-12)) ** 1.5
                    count += 1
            score = -prod_log if count > 0 else 0
            score += np.random.uniform(-0.05, 0.05)
        else:
            score = 0
            for x in range(1, 20):
                inner_sum = 0
                for y in range(1, x + 1):
                    inner_sum += (ratio ** y) / (y + 1)
                score += ((-1) ** x) * inner_sum / (x + 1)
            score = abs(score) * 3 + np.random.uniform(0, 0.2)
        if score < 0:
            score = abs(score) + np.random.uniform(0, 0.1)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority * 4 + np.random.uniform(0, 1)
    else:
        priorities[:] = 1
    return priorities
